pub fn validate_async_payload(
    precompile_address: Address,
    input: &[u8],
    max_ttl: u64,
) -> Result<(), PayloadValidationError> {
    let metadata = metadata_by_address(precompile_address)
        .ok_or(PayloadValidationError::UnknownPrecompile(precompile_address))?;
    if input.len() > MAX_ASYNC_INPUT_SIZE {
        return Err(PayloadValidationError::InputTooLarge { size: input.len(), max: MAX_ASYNC_INPUT_SIZE });
    }

    match metadata.address {
        HTTP_CALL_PRECOMPILE => validate_http_call_payload(input, max_ttl),
        LLM_CALL_PRECOMPILE => validate_llm_call_payload(input, max_ttl),
        LONG_RUNNING_HTTP_PRECOMPILE => validate_long_running_http_payload(input, max_ttl),
        ZK_TWO_PHASE_PRECOMPILE => validate_zk_two_phase_payload(input, max_ttl),
        FHE_PRECOMPILE => validate_fhe_call_payload(input, max_ttl),
        SOVEREIGN_AGENT_PRECOMPILE => validate_sovereign_agent_payload(input, max_ttl),
        IMAGE_CALL_PRECOMPILE | AUDIO_CALL_PRECOMPILE | VIDEO_CALL_PRECOMPILE => {
            validate_executor_request_payload(input, max_ttl)
        }
        DKMS_KEY_PRECOMPILE => validate_dkms_key_payload(input, max_ttl),
        PERSISTENT_AGENT_PRECOMPILE => validate_persistent_agent_payload(input, max_ttl),
        _ => Err(PayloadValidationError::UnknownPrecompile(precompile_address)),
    }
}
