fn validate_http_call_payload(input: &[u8], max_ttl: u64) -> Result<(), PayloadValidationError> {
    let request = HTTPCallRequest::from_abi(input).map_err(decode_error("HTTPCallRequest"))?;
    validate_executor_base_fields(request.executor, request.ttl, &request.encrypted_secrets, &request.user_public_key, max_ttl)?;
    validate_required_http_url(&request.url)
}

fn validate_llm_call_payload(input: &[u8], max_ttl: u64) -> Result<(), PayloadValidationError> {
    let request = LLMCallRequest::from_abi(input).map_err(decode_error("LLMCallRequest"))?;
    validate_executor_base_fields(request.executor, request.ttl, &request.encrypted_secrets, &request.user_public_key, max_ttl)?;
    if request.model.trim().is_empty() { return Err(PayloadValidationError::EmptyModel); }
    if !request.has_valid_messages() { return Err(PayloadValidationError::EmptyMessages); }
    Ok(())
}

fn validate_executor_and_ttl_bounds(executor: Address, ttl: u64, max_ttl: u64) -> Result<(), PayloadValidationError> {
    if executor.is_zero() { return Err(PayloadValidationError::ExecutorZeroAddress); }
    if ttl == 0 { return Err(PayloadValidationError::TtlZero); }
    if ttl > max_ttl { return Err(PayloadValidationError::TtlExceeded { ttl, max: max_ttl }); }
    Ok(())
}

